            <button onclick="document.getElementById\('setFuModal'\).style.display='none'" style="background:#999;">Cancel</button>
          </div>
        </div>
      </div>

      <script>
      \(function\(\) {
        var currentFilter = 'all';
        var pendingSnoozeQn = null;
        var dashboardData = [];

        var i18n = {
          en: {
            fuTitle: 'Follow-Up Reminders',
            back: 'Back',
            overdue: 'Overdue',
            today: 'Due Today',
            upcoming: 'Upcoming',
            completed: 'Completed',
            all: 'All',
            snoozed: 'Snoozed',
            snooze: 'Snooze',
            complete: 'Complete',
            snoozeTitle: 'Snooze Follow-Up',
            snoozeText: 'Choose how long to snooze:',
            day1: '1 Day',
            day3: '3 Days',
            week1: '1 Week',
            cancel: 'Cancel',
            setFuTitle: 'Set Follow-Up Date',
            save: 'Save',
            thQn: 'Q#',
            thClient: 'Client',
            thCompany: 'Company',
            thPrice: 'Price',
            thDate: 'Follow-Up Date',
            thStatus: 'Status',
            thDays: 'Days',
            thActions: 'Actions',
            noData: 'No follow-ups found',
            loading: 'Loading',
            daysOverdue: '{0} days overdue',
            daysAway: 'in {0} days',
            todayLabel: 'Today',
            overdueCount: 'Overdue',
            todayCount: 'Due Today',
            upcomingCount: 'Upcoming',
            completedCount: 'Completed'
          },
          ar: {
            fuTitle: '\\u062a\\u0630\\u0643\\u064a\\u0631\\u0627\\u062a \\u0627\\u0644\\u0645\\u062a\\u0627\\u0628\\u0639\\u0629',
            back: '\\u0631\\u062c\\u0648\\u0639',
            overdue: '\\u0645\\u062a\\u0623\\u062e\\u0631',
            today: '\\u0627\\u0644\\u064a\\u0648\\u0645',
            upcoming: '\\u0642\\u0627\\u062f\\u0645\\u0629',
            completed: '\\u0645\\u0643\\u062a\\u0645\\u0644\\u0629',
            all: '\\u0627\\u0644\\u0643\\u0644',
            snoozed: '\\u0645\\u0624\\u062c\\u0644\\u0629',
            snooze: '\\u062a\\u0623\\u062c\\u064a\\u0644',
            complete: '\\u0625\\u062a\\u0645\\u0627\\u0645',
            snoozeTitle: '\\u062a\\u0623\\u062c\\u064a\\u0644 \\u0627\\u0644\\u0645\\u062a\\u0627\\u0628\\u0639\\u0629',
            snoozeText: '\\u0627\\u062e\\u062a\\u0631 \\u0645\\u062f\\u0629 \\u0627\\u0644\\u062a\\u0623\\u062c\\u064a\\u0644:',
            day1: '\\u064a\\u0648\\u0645 \\u0648\\u0627\\u062d\\u062f',
            day3: '3 \\u0623\\u064a\\u0627\\u0645',
            week1: '\\u0623\\u0633\\u0628\\u0648\\u0639',
            cancel: '\\u0625\\u0644\\u063a\\u0627\\u0621',
            setFuTitle: '\\u062a\\u0639\\u064a\\u064a\\u0646 \\u062a\\u0627\\u0631\\u064a\\u062e \\u0627\\u0644\\u0645\\u062a\\u0627\\u0628\\u0639\\u0629',
            save: '\\u062d\\u0641\\u0638',
            thQn: '\\u0631\\u0642\\u0645 \\u0627\\u0644\\u0639\\u0631\\u0636',
            thClient: '\\u0627\\u0644\\u0639\\u0645\\u064a\\u0644',
