            overdueCount: '\\u0645\\u062a\\u0623\\u062e\\u0631\\u0629',
            todayCount: '\\u0645\\u0633\\u062a\\u062d\\u0642\\u0629 \\u0627\\u0644\\u064a\\u0648\\u0645',
            upcomingCount: '\\u0642\\u0627\\u062f\\u0645\\u0629',
            completedCount: '\\u0645\\u0643\\u062a\\u0645\\u0644\\u0629'
          }
        };

        function t\(key\) {
          var lang = \(window._appLang || 'en'\);
          return \(i18n[lang] && i18n[lang][key]\) || \(i18n['en'][key]\) || key;
        }

        function applyLang\(\) {
          var lang = \(window._appLang || 'en'\);
          var wrapper = document.querySelector\('.fu-wrapper'\);
          if \(wrapper\) {
            wrapper.setAttribute\('dir', lang === 'ar' ? 'rtl' : 'ltr'\);
          }
          var el = document.getElementById\('fuTitle'\);
          if \(el\) el.textContent = t\('fuTitle'\);
          var backBtn = document.querySelector\('.fu-back-btn'\);
          if \(backBtn\) backBtn.textContent = t\('back'\);
          var st = document.getElementById\('snoozeTitle'\);
          if \(st\) st.textContent = t\('snoozeTitle'\);
          var stx = document.getElementById\('snoozeText'\);
          if \(stx\) stx.textContent = t\('snoozeText'\);
          var sft = document.getElementById\('setFuTitle'\);
          if \(sft\) sft.textContent = t\('setFuTitle'\);
        }

        function renderStats\(stats\) {
          var row = document.getElementById\('statsRow'\);
          if \(!row\) return;
          var cards = [
            { key: 'overdue', label: t\('overdueCount'\), cls: 'card-red', val: stats.overdue || 0 },
            { key: 'today', label: t\('todayCount'\), cls: 'card-orange', val: stats.today || 0 },
            { key: 'upcoming', label: t\('upcomingCount'\), cls: 'card-blue', val: stats.upcoming || 0 },
            { key: 'completed', label: t\('completedCount'\), cls: 'card-green', val: stats.completed || 0 }
          ];
          row.innerHTML = '';
          cards.forEach\(function\(c\) {
            var div = document.createElement\('div'\);
            div.className = 'stat-card ' + c.cls;
            div.innerHTML = '<div class="stat-value">' + c.val + '</div><div class="stat-label">' + c.label + '</div>';
            row.appendChild\(div\);
          }\);
        }

        function renderFilters\(\) {
          var row = document.getElementById\('filtersRow'\);
          if \(!row\) return;
          var filters = [
            { key: 'all', label: t\('all'\) },
            { key: 'overdue', label: t\('overdue'\) },
            { key: 'today', label: t\('today'\) },
            { key: 'upcoming', label: t\('upcoming'\) },
            { key: 'completed', label: t\('completed'\) }
          ];
          row.innerHTML = '';
          filters.forEach\(function\(f\) {
            var btn = document.createElement\('button'\);
            btn.className = 'fu-filter-btn' + \(currentFilter === f.key ? ' active' : ''\);
            btn.textContent = f.label;
            btn.onclick = function\(\) { window._fuSetFilter\(f.key\); };
            row.appendChild\(btn\);
          }\);
        }

        function renderTable\(data\) {
          var head = document.getElementById\('tableHead'\);
          var body = document.getElementById\('tableBody'\);
          if \(!head || !body\) return;

          head.innerHTML = '';
          var cols = ['thQn','thClient','thCompany','thPrice','thDate','thStatus','thDays','thActions'];
          cols.forEach\(function\(c\) {
            var th = document.createElement\('th'\);
            th.textContent = t\(c\);
            head.appendChild\(th\);
          }\);

          body.innerHTML = '';
          if \(!data || data.length === 0\) {
            body.innerHTML = '<tr><td colspan="8" class="fu-empty">' + t\('noData'\) + '</td></tr>';
            return;
          }

          data.forEach\(function\(row\) {
            var tr = document.createElement\('tr'\);

            // Q#
            var tdQn = document.createElement\('td'\);
            tdQn.textContent = row.quotation_number || '';
            tr.appendChild\(tdQn\);

            // Client
            var tdClient = document.createElement\('td'\);
            tdClient.textContent = row.client_name || '';
            tr.appendChild\(tdClient\);

            // Company
            var tdCompany = document.createElement\('td'\);
            tdCompany.textContent = row.company_name || '';
            tr.appendChild\(tdCompany\);

            // Price
            var tdPrice = document.createElement\('td'\);
            tdPrice.textContent = row.total_price || '';
            tr.appendChild\(tdPrice\);

            // Follow-Up Date
            var tdDate = document.createElement\('td'\);
            tdDate.textContent = row.follow_up_date || '';
            tr.appendChild\(tdDate\);

            // Status badge
            var tdStatus = document.createElement\('td'\);
            var badge = document.createElement\('span'\);
            badge.className = 'badge';
            if \(row.follow_up_status === 'snoozed'\) {
              badge.classList.add\('badge-snoozed'\);
              badge.textContent = t\('snoozed'\);
            } else if \(row.category === 'overdue'\) {
              badge.classList.add\('badge-overdue'\);
              badge.textContent = t\('overdue'\);
            } else if \(row.category === 'today'\) {
              badge.classList.add\('badge-today'\);
              badge.textContent = t\('today'\);
            } else if \(row.category === 'upcoming'\) {
              badge.classList.add\('badge-upcoming'\);
              badge.textContent = t\('upcoming'\);
            } else if \(row.category === 'completed'\) {
              badge.classList.add\('badge-completed'\);
              badge.textContent = t\('completed'\);
            }
            tdStatus.appendChild\(badge\);
            tr.appendChild\(tdStatus\);

            // Days column
            var tdDays = document.createElement\('td'\);
            if \(row.category === 'overdue'\) {
              tdDays.style.color = '#f44336';
              tdDays.textContent = t\('daysOverdue'\).replace\('{0}', Math.abs\(row.days_until || 0\)\);
            } else if \(row.category === 'today'\) {
              tdDays.style.color = '#ff9800';
              tdDays.textContent = t\('todayLabel'\);
            } else if \(row.category === 'upcoming'\) {
              tdDays.style.color = '#1976d2';
              tdDays.textContent = t\('daysAway'\).replace\('{0}', row.days_until || 0\);
            } else if \(row.category === 'completed'\) {
              tdDays.innerHTML = '\\u2714';
              tdDays.style.color = '#4caf50';
            }
            tr.appendChild\(tdDays\);

            // Actions column
            var tdActions = document.createElement\('td'\);
            if \(row.category !== 'completed'\) {
              var btnSnooze = document.createElement\('button'\);
              btnSnooze.className = 'btn-action btn-snooze';
              btnSnooze.textContent = t\('snooze'\);
              btnSnooze.onclick = \(function\(qn\) {
                return function\(\) { window._fuShowSnooze\(qn\); };
              }\)\(row.quotation_number\);
              tdActions.appendChild\(btnSnooze\);

              var btnComplete = document.createElement\('button'\);
              btnComplete.className = 'btn-action btn-complete';
              btnComplete.textContent = t\('complete'\);
              btnComplete.onclick = \(function\(qn\) {
                return function\(\) { window._fuComplete\(qn\); };
              }\)\(row.quotation_number\);
              tdActions.appendChild\(btnComplete\);
            } else {
              tdActions.innerHTML = '<span style="color:#4caf50;">\\u2714</span>';
            }
            tr.appendChild\(tdActions\);

            body.appendChild\(tr\);
          }\);
        }

        function loadDashboard\(\) {
          if \(!window.pyGetFollowupDashboard\) return;
          window.pyGetFollowupDashboard\(currentFilter\).then\(function\(result\) {
            if \(result && result.stats\) {
              renderStats\(result.stats\);
            }
            dashboardData = \(result && result.data\) || [];
            renderFilters\(\);
            renderTable\(dashboardData\);
          }\).catch\(function\(err\) {
            console.error\('Failed to load follow-up dashboard:', err\);
          }\);
        }

        function init\(\) {
          applyLang\(\);
          if \(window.pyCheckOverdue\) {
            window.pyCheckOverdue\(\).then\(function\(\) {
              loadDashboard\(\);
            }\).catch\(function\(\) {
              loadDashboard\(\);
            }\);
          } else {
            loadDashboard\(\);
          }
        }

        window._fuSetFilter = function\(f\) {
          currentFilter = f;
          loadDashboard\(\);
        };

        window._fuShowSnooze = function\(qn\) {
          pendingSnoozeQn = qn;
          var modal = document.getElementById\('snoozeModal'\);
          if \(modal\) modal.style.display = 'flex';
        };

        window._fuSnooze = function\(days\) {
          if \(!pendingSnoozeQn || !window.pySnoozeFollowup\) return;
          window.pySnoozeFollowup\(pendingSnoozeQn, days\).then\(function\(\) {
            var modal = document.getElementById\('snoozeModal'\);
            if \(modal\) modal.style.display = 'none';
            pendingSnoozeQn = null;
            loadDashboard\(\);
          }\).catch\(function\(err\) {
            console.error\('Snooze failed:', err\);
          }\);
        };

        window._fuComplete = function\(qn\) {
          if \(!window.pyCompleteFollowup\) return;
          window.pyCompleteFollowup\(qn\).then\(function\(\) {
            loadDashboard\(\);
          }\).catch\(function\(err\) {
            console.error\('Complete failed:', err\);
          }\);
        };

        window._fuShowSetDate = function\(qn\) {
          pendingSnoozeQn = qn;
          var modal = document.getElementById\('setFuModal'\);
          if \(modal\) modal.style.display = 'flex';
        };

        window._fuSaveDate = function\(\) {
          var input = document.getElementById\('setFuDateInput'\);
          if \(!input || !input.value || !pendingSnoozeQn || !window.pySetFollowup\) return;
          window.pySetFollowup\(pendingSnoozeQn, input.value\).then\(function\(\) {
            var modal = document.getElementById\('setFuModal'\);
            if \(modal\) modal.style.display = 'none';
            pendingSnoozeQn = null;
            loadDashboard\(\);
          }\).catch\(function\(err\) {
            console.error\('Set follow-up failed:', err\);
          }\);
        };

        function waitForBridge\(\) {
          if \(window.pyGetFollowupDashboard\) {
            init\(\);
          } else {
            setTimeout\(waitForBridge, 100\);
          }
        }

        if \(document.readyState === 'loading'\) {
          document.addEventListener\('DOMContentLoaded', waitForBridge\);
        } else {
          waitForBridge\(\);
        }
      }\)\(\);
      </script>
